-- Fix services using DID products with corrected wholesale costs
UPDATE services SET monthlyCost=0.20, costSource='product_map' WHERE planName='DID Australia (1)';
UPDATE services SET monthlyCost=2.00, costSource='product_map' WHERE planName='DID Australia (10)';
UPDATE services SET monthlyCost=20.00, costSource='product_map' WHERE planName='DID Australia (100)';
UPDATE services SET monthlyCost=14.95, costSource='product_map' WHERE planName='Direct In Dial AU Mobile Number (1)';
UPDATE services SET monthlyCost=5.00, costSource='product_map' WHERE planName='Inbound 1300 Number Hosting';
UPDATE services SET monthlyCost=5.00, costSource='product_map' WHERE planName='Inbound 1800 Number Hosting';

-- Verify the service updates
SELECT planName, COUNT(*) as cnt, MIN(monthlyCost) as minCost, MAX(monthlyCost) as maxCost
FROM services
WHERE planName IN (
  'DID Australia (1)', 'DID Australia (10)', 'DID Australia (100)',
  'Direct In Dial AU Mobile Number (1)', 'Inbound 1300 Number Hosting', 'Inbound 1800 Number Hosting'
)
GROUP BY planName ORDER BY planName;

